var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"훗, 모두 해치웠나?","JPN":"ふっ、やったか？","ENG":"Hmph. Did we win?","TWN":"呼～敵人都解決掉了吧？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"그런 말 하지 마, 바보야! 적이 부활하는 클리셰라고!","JPN":"そんなこと言わないで、バカ！　それは敵の生存フラグだよ！","ENG":"Don’t say that, stupid! That’s what people say when the enemies get back up and fight!","TWN":"這種話不能說啦，笨蛋！你不知道每次說完這句話，敵人就又會跑出來嗎！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"이거 봐, 숫자가 늘어났잖아!","JPN":"ほら見なさいよ、数が増えたじゃん！","ENG":"See?! They’ve multiplied!!","TWN":"你看啦，又來了！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"침착해라, 소녀여.","JPN":"落ち着け、少女よ。","ENG":"Stay calm, girl.","TWN":"冷靜點，少女！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"적이 늘어나면 그만큼 더 쓰러뜨리면 그만이다.","JPN":"敵が増えたなら、増えた分また倒せばいいだけのこと。","ENG":"More enemies simply mean that we must eliminate more of them.","TWN":"敵人來了又怎樣，來一個我殺一個！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"리더. 작전상 후퇴를 제안합니다.","JPN":"リーダー。戦略的撤退を提案します。","ENG":"Leader. I suggest a tactical retreat.","TWN":"老大，我建議撤退。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"후퇴라고? 그런 비겁한 행동은 용납할 수 없다!","JPN":"撤退だって？　そんな卑怯な真似は許さん！","ENG":"Retreat? I will not allow such cowardice!","TWN":"撤退？我不能接受這種卑劣的做法！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"적의 규모도 모르는 상태야. 이런 좁은 건물에서 수세에 몰리면 우리만 불리해져.","JPN":"敵の規模すらつかめてない状態です。\\nこんな狭い建物の中で追い込まれたら、私たちが不利になるだけ。","ENG":"We don’t know how many more of them are out there. If we get overwhelmed in this tiny building, we’re doomed.","TWN":"我們現在無法掌握敵人的數量有多少，在這麼窄的建築物裡做困獸之鬥，反而對我們不利。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"그러니 작전상 후퇴 후에 적의 가족들을 인질로 잡고 협상한다.","JPN":"だから、戦略的撤退の後に敵の家族を人質にとって交渉しましょう。","ENG":"Thus, we make a tactical retreat, grab the enemies’ families as hostages and parley.","TWN":"所以我建議先撤退，然後再抓敵人的家人為人質，作為談判的籌碼。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"그냥 비겁한 게 아니라 엄청 비겁한 것 아닌가! 이 무시무시한 인간 같으니!","JPN":"ただの卑怯者ではなく、最低最悪の卑怯者じゃないか！\\nなんて恐ろしい人間なんだ！","ENG":"That’s not just cowardice, that’s being despicable! You nasty, nasty person!","TWN":"哇，你這不只是卑劣，而是超級卑劣！你這可怕的人類！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CHOWON_ALPHA_NULL_NULL","text":{"KOREA":"손가락을 우편으로 보내면 저들도 우리의 결사 항전 의지를 알아 줄 테고.","JPN":"人質の指を送ってやれば、向こうにも私たちの決死の覚悟が伝わるでしょうし。","ENG":"If we mail them their families' fingers, they’ll know we aren’t messing around.","TWN":"我們可以把人質的手指寄去給對方，對方就會知道我們誓死抵抗的決心。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOWON_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"소름끼치는 농담 하지 마! 꿈에서 나올 것 같잖아!","JPN":"そんな恐ろしい冗談言わないでよね！　夢に出そうじゃん！","ENG":"C’mon! Cut it out! You’re gonna give me nightmares!","TWN":"你不要開這種可怕的玩笑啦！我會晚上做惡夢欸！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"침착하세요, 여러분.","JPN":"落ち着いてください、みなさん。","ENG":"Everyone, just stay calm.","TWN":"大家冷靜點。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"잠시 무기를 거둬 주세요. 상대도 대화를 원하는 것 같아요.","JPN":"しばらく武器をしまってください。相手も話し合いを望んでいるようです。","ENG":"Lower your weapons. I think they want to talk.","TWN":"先把武器收起來，對方似乎想和我們談話。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};